[
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 176,
    "severity": "high",
    "description": "Returned state values do not reflect auto-opt-in transformation. Lines 152-159 apply auto-opt-in transformation to compute effective states, which are used for computing effectiveEnabled. However, lines 176-178 return the original untransformed states (orgState, teamStates, userState). This violates the documented behavior in the method's docstring (lines 88-91) which states 'If autoOptInFeatures=true at a level AND state is "inherit", transform to "enabled"'. Callers will see inconsistent data where a state might be 'inherit' but effectiveEnabled is true due to auto-opt-in.",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -173,9 +173,9 @@
     return {
       featureId,
       globalEnabled,
-      orgState,
-      teamStates,
-      userState,
+      orgState: effectiveOrgState,
+      teamStates: effectiveTeamStates,
+      userState: effectiveUserState,
       effectiveEnabled,
       effectiveReason,
       orgAutoOptIn,
"
  },
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 103,
    "severity": "critical",
    "description": "Incorrect parameter passing violates union type contract. The setUserFeatureState method expects a union type where assignedBy is only provided when state is 'enabled' or 'disabled', not when state is 'inherit'. However, the router always provides assignedBy regardless of the state value. This violates the method's type contract and causes incorrect behavior when state is 'inherit'.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -100,11 +100,18 @@
         });
       }

-      await featureOptInService.setUserFeatureState({
-        userId: ctx.user.id,
-        featureId: input.slug,
-        state: input.state,
-        assignedBy: ctx.user.id,
-      });
+      if (input.state === "inherit") {
+        await featureOptInService.setUserFeatureState({
+          userId: ctx.user.id,
+          featureId: input.slug,
+          state: input.state,
+        });
+      } else {
+        await featureOptInService.setUserFeatureState({
+          userId: ctx.user.id,
+          featureId: input.slug,
+          state: input.state,
+          assignedBy: ctx.user.id,
+        });
+      }

       return { success: true };
"
  },
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 131,
    "severity": "critical",
    "description": "Incorrect parameter passing violates union type contract. Same issue as setUserState - the setTeamFeatureState method expects assignedBy only when state is 'enabled' or 'disabled', but the router always provides it regardless of state value.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -128,12 +128,19 @@
         });
       }

-      await featureOptInService.setTeamFeatureState({
-        teamId: input.teamId,
-        featureId: input.slug,
-        state: input.state,
-        assignedBy: ctx.user.id,
-        scope: "team",
-      });
+      if (input.state === "inherit") {
+        await featureOptInService.setTeamFeatureState({
+          teamId: input.teamId,
+          featureId: input.slug,
+          state: input.state,
+          scope: "team",
+        });
+      } else {
+        await featureOptInService.setTeamFeatureState({
+          teamId: input.teamId,
+          featureId: input.slug,
+          state: input.state,
+          assignedBy: ctx.user.id,
+          scope: "team",
+        });
+      }

       return { success: true };
"
  },
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 161,
    "severity": "critical",
    "description": "Incorrect parameter passing violates union type contract. Same issue as previous mutations - the setTeamFeatureState call (used for organization scope) always provides assignedBy even when state is 'inherit', violating the method's union type contract.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -158,12 +158,19 @@
         });
       }

-      // Organizations use the same TeamFeatures table
-      await featureOptInService.setTeamFeatureState({
-        teamId: ctx.organizationId,
-        featureId: input.slug,
-        state: input.state,
-        assignedBy: ctx.user.id,
-        scope: "org",
-      });
+      // Organizations use the same TeamFeatures table
+      if (input.state === "inherit") {
+        await featureOptInService.setTeamFeatureState({
+          teamId: ctx.organizationId,
+          featureId: input.slug,
+          state: input.state,
+          scope: "org",
+        });
+      } else {
+        await featureOptInService.setTeamFeatureState({
+          teamId: ctx.organizationId,
+          featureId: input.slug,
+          state: input.state,
+          assignedBy: ctx.user.id,
+          scope: "org",
+        });
+      }

       return { success: true };
"
  }
]

